SELECT ds.session_id, ds.session_name, ds.defense_date, ds.start_time, ds.end_time, ds.location, ds.defense_form, ds.academic_year, ds.campus_name, ds.teacher_id, ds.file_id, df.original_name AS file_name, df.file_size, df.mime_type, ds.remark, ds.create_time FROM defense_session ds LEFT JOIN doc_file df ON ds.file_id = df.file_id AND df.is_deleted = 0 WHERE ds.is_deleted = 0
AND ds.campus_name = #{campusName}
AND ds.academic_year = #{academicYear}
AND (ds.session_name LIKE CONCAT('%', #{keyword}, '%') OR ds.location LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY ds.defense_date DESC, ds.start_time ASC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM defense_session ds WHERE ds.is_deleted = 0
AND ds.campus_name = #{campusName}
AND ds.academic_year = #{academicYear}
AND (ds.session_name LIKE CONCAT('%', #{keyword}, '%') OR ds.location LIKE CONCAT('%', #{keyword}, '%'))

SELECT ds.session_id, ds.session_name, ds.defense_date, ds.start_time, ds.end_time, ds.location, ds.defense_form, ds.academic_year, ds.campus_name, ds.teacher_id, ds.file_id, df.original_name AS file_name, df.file_size, df.mime_type, ds.remark, ds.create_time FROM defense_session ds LEFT JOIN doc_file df ON ds.file_id = df.file_id AND df.is_deleted = 0 WHERE ds.is_deleted = 0 AND ds.teacher_id = #{teacherId}
AND ds.academic_year = #{academicYear}
AND (ds.session_name LIKE CONCAT('%', #{keyword}, '%') OR ds.location LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY ds.defense_date DESC, ds.start_time ASC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM defense_session ds WHERE ds.is_deleted = 0 AND ds.teacher_id = #{teacherId}
AND ds.academic_year = #{academicYear}
AND (ds.session_name LIKE CONCAT('%', #{keyword}, '%') OR ds.location LIKE CONCAT('%', #{keyword}, '%'))

SELECT DISTINCT ds.session_id, ds.session_name, ds.defense_date, ds.start_time, ds.end_time, ds.location, ds.defense_form, ds.academic_year, ds.campus_name, ds.teacher_id, ds.file_id, df.original_name AS file_name, df.file_size, df.mime_type, ds.remark, ds.create_time FROM defense_session ds INNER JOIN project_selection ps ON ps.campus_name = ds.campus_name AND ps.is_deleted = 0 AND ps.status = 'APPROVED' LEFT JOIN doc_file df ON ds.file_id = df.file_id AND df.is_deleted = 0 WHERE ds.is_deleted = 0 AND ps.student_id = #{studentId}
AND ds.academic_year = #{academicYear}
ORDER BY ds.defense_date DESC, ds.start_time ASC LIMIT #{offset}, #{limit}

SELECT COUNT(DISTINCT ds.session_id)
FROM defense_session ds
INNER JOIN project_selection ps ON ps.campus_name = ds.campus_name AND ps.is_deleted = 0 AND ps.status = 'APPROVED'
WHERE ds.is_deleted = 0
AND ps.student_id = #{studentId}

    AND ds.academic_year = #{academicYear}

SELECT da.arrange_id, da.session_id, ds.session_name, ds.defense_date, ds.start_time, ds.end_time, ds.location, ds.defense_form, ds.academic_year, ds.file_id, df.original_name AS file_name, ds.remark, da.selection_id, da.student_id, su.real_name AS student_name, su.student_no, pt.topic_name, ps.custom_topic_name, ps.is_custom_topic, da.teacher_id, tu.real_name AS teacher_name, da.create_time FROM defense_arrangement da INNER JOIN defense_session ds ON da.session_id = ds.session_id AND ds.is_deleted = 0 INNER JOIN project_selection ps ON da.selection_id = ps.selection_id AND ps.is_deleted = 0 INNER JOIN sys_user su ON da.student_id = su.user_id AND su.is_deleted = 0 LEFT JOIN project_topic pt ON pt.topic_id = ps.topic_id AND pt.is_deleted = 0 LEFT JOIN sys_user tu ON ps.teacher_id = tu.user_id AND tu.is_deleted = 0 LEFT JOIN doc_file df ON ds.file_id = df.file_id AND df.is_deleted = 0 WHERE da.is_deleted = 0
AND da.session_id = #{sessionId}
AND (su.real_name LIKE CONCAT('%', #{keyword}, '%') OR su.student_no LIKE CONCAT('%', #{keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY da.sort_order ASC, da.create_time ASC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM defense_arrangement da INNER JOIN defense_session ds ON da.session_id = ds.session_id AND ds.is_deleted = 0 INNER JOIN project_selection ps ON da.selection_id = ps.selection_id AND ps.is_deleted = 0 INNER JOIN sys_user su ON da.student_id = su.user_id AND su.is_deleted = 0 LEFT JOIN project_topic pt ON pt.topic_id = ps.topic_id AND pt.is_deleted = 0 WHERE da.is_deleted = 0
AND da.session_id = #{sessionId}
AND (su.real_name LIKE CONCAT('%', #{keyword}, '%') OR su.student_no LIKE CONCAT('%', #{keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{keyword}, '%'))
